# Allowed image content types and max file size
ALLOWED_CONTENT_TYPES = frozenset({
    "image/jpeg",
    "image/png",
    "image/gif",
    "image/webp",
})
MAX_FILE_SIZE_BYTES = 10 * 1024 * 1024  # 10 MB

# Allowed S3 key prefix for uploads (prevent path traversal)
ALLOWED_UPLOAD_PREFIX = "uploads/"

# Read configuration from environment variables (set in Lambda config, not hardcoded)
UPLOAD_BUCKET = os.environ.get("UPLOAD_BUCKET")
RESULTS_BUCKET = os.environ.get("RESULTS_BUCKET")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN")

# Initialize clients outside handler for connection reuse across invocations
s3_client = boto3.client("s3")
sns_client = boto3.client("sns")


class ImageValidationError(Exception):
    """Raised when an uploaded image fails validation checks."""
    pass


class ConfigurationError(Exception):
    """Raised when required environment configuration is missing."""
    pass


def validate_configuration():
    """Validate that all required environment variables are set."""
    missing = []
    if not UPLOAD_BUCKET:
        missing.append("UPLOAD_BUCKET")
    if not RESULTS_BUCKET:
        missing.append("RESULTS_BUCKET")
    if not SNS_TOPIC_ARN:
        missing.append("SNS_TOPIC_ARN")
    if missing:
        raise ConfigurationError(
            f"Missing required environment variables: {', '.join(missing)}"
        )


def validate_s3_key(key):
    """
    Validate the S3 object key to prevent path traversal and ensure it is
    within the expected upload prefix.
    """
    # Decode URL-encoded key
    decoded_key = unquote_plus(key)

    # Reject path traversal attempts
    if ".." in decoded_key or decoded_key.startswith("/"):
        raise ImageValidationError(
            f"Invalid S3 key (potential path traversal): {decoded_key}"
        )

    # Ensure key is within the allowed prefix
    if not decoded_key.startswith(ALLOWED_UPLOAD_PREFIX):
        raise ImageValidationError(
            f"S3 key '{decoded_key}' is not within allowed prefix '{ALLOWED_UPLOAD_PREFIX}'"
        )

    return decoded_key


def validate_bucket_name(bucket_name):
    """Ensure the event references only the expected upload bucket."""
    if bucket_name != UPLOAD_BUCKET:
        raise ImageValidationError(
            f"Unexpected source bucket '{bucket_name}'. Expected '{UPLOAD_BUCKET}'."
        )


def validate_image_metadata(bucket, key):
    """
    Fetch object metadata and validate content type and size before
    downloading the full object.
    """
    try:
        head_response = s3_client.head_object(Bucket=bucket, Key=key)
    except ClientError as e:
        error_code = e.response.get("Error", {}).get("Code", "Unknown")
        raise ImageValidationError(
            f"Cannot retrieve metadata for s3://{bucket}/{key}: {error_code}"
        ) from e

    content_type = head_response.get("ContentType", "")
    content_length = head_response.get("ContentLength", 0)

    if content_type not in ALLOWED_CONTENT_TYPES:
        raise ImageValidationError(
            f"Disallowed content type '{content_type}'. "
            f"Allowed: {', '.join(sorted(ALLOWED_CONTENT_TYPES))}"
        )

    if content_length > MAX_FILE_SIZE_BYTES:
        raise ImageValidationError(
            f"File size {content_length} bytes exceeds maximum "
            f"allowed {MAX_FILE_SIZE_BYTES} bytes."
        )

    if content_length == 0:
        raise ImageValidationError("File is empty (0 bytes).")

    return {
        "content_type": content_type,
        "content_length": content_length,
        "last_modified": str(head_response.get("LastModified", "")),
    }


def read_image_from_s3(bucket, key):
    """Download image bytes from S3."""
    try:
        response = s3_client.get_object(Bucket=bucket, Key=key)
        image_data = response["Body"].read()
        return image_data
    except ClientError as e:
        error_code = e.response.get("Error", {}).get("Code", "Unknown")
        logger.error(
            "Failed to read s3://%s/%s: %s", bucket, key, error_code
        )
        raise


def process_image(image_data, metadata):
    """
    Process the image data. This is the placeholder for your actual
    image processing logic (resize, thumbnail, ML inference, etc.).

    Returns a dict with processing results and optionally transformed image bytes.
    """
    # --- Replace this section with actual image processing ---
    result = {
        "status": "processed",
        "original_size_bytes": len(image_data),
        "content_type": metadata["content_type"],
        "processing_notes": "placeholder - add real processing logic",
    }

    # For MVP: return original image data as the "processed" output
    processed_image_data = image_data

    return result, processed_image_data


def build_results_key(original_key):
    """
    Build the S3 key for the results object. Uses a unique suffix to
    avoid overwriting previous results.
    """
    # Strip the upload prefix and build a results path
    relative_key = original_key
    if relative_key.startswith(ALLOWED_UPLOAD_PREFIX):
        relative_key = relative_key[len(ALLOWED_UPLOAD_PREFIX):]

    # Sanitize: only allow alphanumeric, hyphens, underscores, dots, slashes
    safe_chars = set(
        "abcdefghijklmnopqrstuvwxyz"
        "ABCDEFGHIJKLMNOPQRSTUVWXYZ"
        "0123456789-_./")
    sanitized = "".join(c if c in safe_chars else "_" for c in relative_key)

    unique_id = uuid.uuid4().hex[:8]
    results_key = f"results/{sanitized}_{unique_id}.json"
    return results_key


def write_results_to_s3(results_key, result_data, processed_image_data, content_type):
    """Write processing results (JSON metadata and processed image) to S3."""
    # Write JSON metadata
    try:
        s3_client.put_object(
            Bucket=RESULTS_BUCKET,
            Key=results_key,
            Body=json.dumps(result_data, default=str),
            ContentType="application/json",
            ServerSideEncryption="aws:kms",
        )
        logger.info("Results metadata written to s3://%s/%s", RESULTS_BUCKET, results_key)
    except ClientError as e:
        logger.error("Failed to write results metadata: %s", e)
        raise

    # Write processed image alongside the metadata
    image_results_key = results_key.rsplit(".json", 1)[0] + _extension_for_type(content_type)
    try:
        s3_client.put_object(
            Bucket=RESULTS_BUCKET,
            Key=image_results_key,
            Body=processed_image_data,
            ContentType=content_type,
            ServerSideEncryption="aws:kms",
        )
        logger.info(
            "Processed image written to s3://%s/%s", RESULTS_BUCKET, image_results_key
        )
    except ClientError as e:
        logger.error("Failed to write processed image: %s", e)
        raise

    return results_key, image_results_key


def _extension_for_type(content_type):
    """Map content type to file extension."""
    mapping = {
        "image/jpeg": ".jpg",
        "image/png": ".png",
        "image/gif": ".gif",
        "image/webp": ".webp",
    }
    return mapping.get(content_type, ".bin")


def send_notification(source_key, results_key, image_results_key, result_data):
    """Publish a processing completion notification to SNS."""
    message = {
        "event": "image_processing_complete",
        "source_key": source_key,
        "results_metadata_key": results_key,
        "processed_image_key": image_results_key,
        "results_bucket": RESULTS_BUCKET,
        "status": result_data.get("status", "unknown"),
    }

    try:
        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject="Image Processing Complete",
            Message=json.dumps(message, default=str),
            MessageAttributes={
                "event_type": {
                    "DataType": "String",
                    "StringValue": "image_processing_complete",
                }
            },
        )
        logger.info("SNS notification sent for key: %s", source_key)
    except ClientError as e:
        # Log but don't fail the whole function if notification fails
        logger.error("Failed to send SNS notification: %s", e)


def send_error_notification(source_key, error_message):
    """Publish an error notification to SNS."""
    message = {
        "event": "image_processing_error",
        "source_key": source_key,
        "error": str(error_message),
    }

    try:
        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject="Image Processing Error",
            Message=json.dumps(message, default=str),
            MessageAttributes={
                "event_type": {
                    "DataType": "String",
                    "StringValue": "image_processing_error",
                }
            },
        )
    except ClientError:
        logger.error("Failed to send error notification for key: %s", source_key)


def process_record(record):
    """Process a single S3 event record."""
    # Extract bucket and key from the S3 event
    s3_info = record.get("s3", {})
    bucket = s3_info.get("bucket", {}).get("name", "")
    raw_key = s3_info.get("object", {}).get("key", "")

    if not bucket or not raw_key:
        logger.warning("Skipping record with missing bucket or key.")
        return None

    # Validate the source bucket
    validate_bucket_name(bucket)

    # Validate and decode the S3 key
    key = validate_s3_key(raw_key)

    logger.info(
        "Processing image: s3://%s/%s",
        bucket,
        key,
    )

    # Validate image metadata (content type, size) before downloading
    metadata = validate_image_metadata(bucket, key)
    logger.info(
        "Image metadata validated: type=%s, size=%d bytes",
        metadata["content_type"],
        metadata["content_length"],
    )

    # Download the image
    image_data = read_image_from_s3(bucket, key)

    # Process the image
    result_data, processed_image_data = process_image(image_data, metadata)
    result_data["source_bucket"] = bucket
    result_data["source_key"] = key
    result_data["metadata"] = metadata

    # Write results to S3
    results_key = build_results_key(key)
    results_key, image_results_key = write_results_to_s3(
        results_key, result_data, processed_image_data, metadata["content_type"]
    )

    # Send success notification
    send_notification(key, results_key, image_results_key, result_data)

    return {
        "source_key": key,
        "results_key": results_key,
        "image_results_key": image_results_key,
        "status": "success",
    }


def lambda_handler(event, context):
    """
    AWS Lambda entry point. Triggered by S3 PutObject events.

    Expected event structure:
    {
        "Records": [
            {
                "s3": {
                    "bucket": {"name": "upload-bucket"},
                    "object": {"key": "uploads/image.jpg"}
                }
            }
        ]
    }
    """
    logger.info(
        "Lambda invoked. Request ID: %s",
        getattr(context, "aws_request_id", "unknown"),
    )

    # Validate environment configuration
    try:
        validate_configuration()
    except ConfigurationError as e:
        logger.error("Configuration error: %s", e)
        return {
            "statusCode": 500,
            "body": json.dumps({"error": "Internal configuration error"}),
        }

    records = event.get("Records", [])
    if not records:
        logger.warning("No records found in event.")
        return {
            "statusCode": 200,
            "body": json.dumps({"message": "No records to process"}),
        }

    results = []
    errors = []

    for record in records:
        source_key = (
            record.get("s3", {}).get("object", {}).get("key", "unknown")
        )
        try:
            result = process_record(record)
            if result:
                results.append(result)
        except ImageValidationError as e:
            logger.warning("Validation failed for %s: %s", source_key, e)
            errors.append({"source_key": source_key, "error": str(e)})
            send_error_notification(source_key, e)
        except ClientError as e:
            logger.error("AWS error processing %s: %s", source_key, e)
            errors.append({"source_key": source_key, "error": str(e)})
            send_error_notification(source_key, e)
        except Exception as e:
            # Catch-all: log the error but don't expose internal details
            logger.exception("Unexpected error processing %s", source_key)
            errors.append({"source_key": source_key, "error": "Internal processing error"})
            send_error_notification(source_key, "Internal processing error")

    response = {
        "statusCode": 200,
        "body": json.dumps(
            {
                "processed": len(results),
                "errors": len(errors),
                "results": results,
                "error_details": errors,
            },
            default=str,
        ),
    }

    logger.info(
        "Processing complete. Processed: %d, Errors: %d",
        len(results),
        len(errors),
    )

    return response